import json
def load(p):
    try: return json.load(open(p))["papers"]
    except Exception as e: print("err",p,e); return []
prim={p["title"] for p in load("paper_search_results/primary_raw.json")}
for name,path in [("MECH","paper_search_results/grounding_mech_raw.json"),("BENCH","paper_search_results/benchmark_raw.json")]:
    ps=load(path)
    print(f"\n==== {name}: {len(ps)} papers, r3={sum(1 for p in ps if p['relevance']==3)} ====")
    for p in ps:
        if p["relevance"]>=3 and p["title"] not in prim:
            print(f"  NEW r{p['relevance']} {str(p.get('year')):>4} c{p['citations']:>4} {p['title'][:88]}")
