export const meta = {
  name: 'extract-paper-notes',
  description: 'Read each downloaded paper PDF and extract structured research notes for a literature review on grounded-novelty scientific idea generation',
  phases: [{ title: 'Read', detail: 'one agent per paper PDF' }],
}

const fs = args // not used; we inline the list below via args path is not readable in sandbox, so caller embeds list

// The caller passes the paper list directly as args.papers
const papers = args.papers

const NOTE_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['arxiv','one_liner','problem','method','grounding_mechanisms','datasets','baselines','metrics','key_results','code_links','relevance_to_hypothesis','limitations'],
  properties: {
    arxiv: { type: 'string' },
    one_liner: { type: 'string', description: 'one sentence summary' },
    problem: { type: 'string' },
    method: { type: 'string', description: '2-5 sentences on the approach/algorithm' },
    grounding_mechanisms: { type: 'array', items: { type: 'string', enum: ['deduction','induction','proposal_writing','outcome_imagination','small_experiments','literature_comparison','none_unguided','other'] }, description: 'which grounding mechanisms from the hypothesis this paper uses or evaluates' },
    grounding_notes: { type: 'string', description: 'how novelty is grounded/operationalized in this paper' },
    datasets: { type: 'array', items: { type: 'string' }, description: 'dataset names with size and any URL/HF id mentioned' },
    baselines: { type: 'array', items: { type: 'string' } },
    metrics: { type: 'array', items: { type: 'string' }, description: 'evaluation metrics, esp. how novelty is measured' },
    key_results: { type: 'string' },
    code_links: { type: 'array', items: { type: 'string' } },
    relevance_to_hypothesis: { type: 'string', description: 'why this matters for: LLMs generate better ideas when novelty is grounded via deduction/induction/proposal/outcome-imagination/small-experiments/literature-comparison vs unguided' },
    limitations: { type: 'string' },
  },
}

const HYP = 'HYPOTHESIS UNDER STUDY: LLMs generate higher quality scientific ideas when novelty is grounded through deduction, induction, proposal writing, outcome imagination, small experiments, or literature comparison, vs. unguided generation.'

const notes = await pipeline(
  papers,
  (p) => {
    const pages = typeof p.pages === 'number' ? p.pages : 30
    const readPlan = p.deep
      ? `This is a FOUNDATIONAL paper — read it deeply. Read the PDF at "${p.file}" in page ranges (the Read tool accepts a pages param, max 20 pages/request). Read pages 1-10, then the methods and experiments sections (continue through the paper, it has ${pages} pages). Capture exact dataset names/sizes, baselines, metrics (especially how novelty is operationalized), and numeric results.`
      : `Read the PDF at "${p.file}" focusing on abstract, intro, method, and experiments/results sections. The Read tool reads PDFs via a pages param (max 20 pages/req). It has ${pages} pages — read the first ~12 pages and skim the experiments/results section. You do NOT need every page.`
    return agent(
      `${HYP}\n\nYou are extracting structured notes for a literature review. Paper: "${p.title}" (arXiv ${p.arxiv}).\nAbstract: ${p.abstract}\n\n${readPlan}\n\nReturn structured notes. Be concrete and faithful to the paper — include exact dataset names, sizes, HuggingFace/GitHub links, baseline names, and metric definitions where stated. For grounding_mechanisms, map the paper's techniques onto the hypothesis's mechanism vocabulary (e.g. retrieval+novelty-comparison-to-prior-papers => literature_comparison; running experiments/feedback => small_experiments; observation->hypothesis => induction; theory->prediction => deduction; writing full proposals => proposal_writing; imagining outcomes/Bayesian-surprise => outcome_imagination).`,
      { label: `read:${p.arxiv}`, phase: 'Read', schema: NOTE_SCHEMA, agentType: 'Explore' }
    ).then(n => ({ ...n, title: p.title, file: p.file, pages: p.pages }))
  }
)

return notes.filter(Boolean)

